import ldap3

def search_ldap_user(server, dn, username, password):
    server = ldap3.Server(server)
    connection = ldap3.Connection(server,
                                  user=f"{dn},{username}",
                                  password=password,
                                  auto_bind=True)

    filter = f"(sAMAccountName={username})"
    attributes = ['sn', 'givenName', 'mail']
    try:
        if connection.bind():
            result = connection.search(search_base=dn, search_filter=filter, attributes=attributes)
            return result
        else:
            raise Exception("LDAP bind failed")
    except ldap3.core.exceptions.LDAPSocketOpenError as e:
        print(f"Failed to connect to LDAP server: {e}")
        return None

